defmodule MyAppWeb.UserController do
  use Phoenix.Controller
  
  alias Ecto.Changeset
  import Plug.Conn
    
  def update(conn, %{"id" => id_param} = params) do
    user =  Repo.get(MyApp.Repo, id_param) # assuming you have a User model with an ID field named :id in your repo and Ecto as the repository module for this app 
    
   changeset  = MyApp.User.changeset(user, params)   
      if Changeset.valid?(changeset) do        
        Repo.update(changeset)          # Update user with new parameters from request body in database          
       {:ok, updated_user} = json(conn, %{message: "User successfully Updated"}) 
      else   
     {:error, changeset }  =  json(conn, %{errors: Changeset.errors(changeset) }) # Return errors if validation fails         
       end        
        conn                
        |> put_status(:ok)          
        |> render("user.json", user: updated_user ) 
    else    
      { :error, changeset }  =  json(conn, %{message: "User not found"}) # Return error if the User is non-existent         
       end        
        conn                
        |> put_status(:not_found)          
        |> render("user.json", message: "No user with such id was found")      
    end  
end